use std::collections::BTreeMap;
use std::io::{self, Read};

const PI_VALUE: f64 = 3.1415926535;
const LT: &str = "LT";
const EQ: &str = "EQ";
const GT: &str = "GT";

fn realcompare(a: f64, b: f64) -> &'static str {
    let scale = a.abs().max(b.abs());
    if scale == 0.0 {
        return "EQ";
    }
    let eps = 0.5e-5 * scale;
    let diff = a - b;
    if diff > eps {
        "GT"
    } else if diff < -eps {
        "LT"
    } else {
        "EQ"
    }
}

fn cmp_gt(a: f64, b: f64) -> bool {
    realcompare(a, b) == GT
}

fn cmp_lt(a: f64, b: f64) -> bool {
    realcompare(a, b) == LT
}

fn cmp_ge(a: f64, b: f64) -> bool {
    let c = realcompare(a, b);
    c == GT || c == EQ
}

fn cmp_le(a: f64, b: f64) -> bool {
    let c = realcompare(a, b);
    c == LT || c == EQ
}

#[derive(Clone, Debug)]
struct Point {
    x: f64,
    y: f64,
}

#[derive(Clone, Debug)]
struct Parameters {
    length1: f64,
    radius1: f64,
    epsilon: f64,
    area1: f64,
    q_pts: usize,
    quads: usize,
    dist: f64,
    n_pts: usize,
    k_pts: usize,
    a_pts: usize,
    b_pts: usize,
    c_pts: usize,
    d_pts: usize,
    e_pts: usize,
    f_pts: usize,
    g_pts: usize,
    length2: f64,
    radius2: f64,
    area2: f64,
}

#[derive(Clone, Copy, Debug)]
enum Connector {
    NotUsed,
    Orr,
    Andd,
}

#[derive(Clone, Debug)]
struct Input {
    numpoints: usize,
    points: Vec<Point>,
    parameters: Parameters,
    lcm: Vec<Vec<Connector>>,
    pum_diag: Vec<bool>,
}

#[derive(Clone, Debug)]
enum JsonValue {
    Null,
    Bool(bool),
    Number(f64),
    String(String),
    Array(Vec<JsonValue>),
    Object(BTreeMap<String, JsonValue>),
}

struct JsonParser<'a> {
    bytes: &'a [u8],
    pos: usize,
}

impl<'a> JsonParser<'a> {
    fn new(src: &'a str) -> Self {
        Self {
            bytes: src.as_bytes(),
            pos: 0,
        }
    }

    fn parse(mut self) -> Result<JsonValue, String> {
        let value = self.parse_value()?;
        self.skip_ws();
        if self.pos != self.bytes.len() {
            return Err("trailing characters after JSON value".to_string());
        }
        Ok(value)
    }

    fn parse_value(&mut self) -> Result<JsonValue, String> {
        self.skip_ws();
        match self.peek() {
            Some(b'n') => self.parse_null(),
            Some(b't') | Some(b'f') => self.parse_bool(),
            Some(b'-') | Some(b'0'..=b'9') => self.parse_number(),
            Some(b'"') => self.parse_string().map(JsonValue::String),
            Some(b'[') => self.parse_array(),
            Some(b'{') => self.parse_object(),
            _ => Err("unexpected character while parsing JSON".to_string()),
        }
    }

    fn parse_null(&mut self) -> Result<JsonValue, String> {
        if self.consume_bytes(b"null") {
            Ok(JsonValue::Null)
        } else {
            Err("invalid null literal".to_string())
        }
    }

    fn parse_bool(&mut self) -> Result<JsonValue, String> {
        if self.consume_bytes(b"true") {
            Ok(JsonValue::Bool(true))
        } else if self.consume_bytes(b"false") {
            Ok(JsonValue::Bool(false))
        } else {
            Err("invalid boolean literal".to_string())
        }
    }

    fn parse_number(&mut self) -> Result<JsonValue, String> {
        let start = self.pos;
        if self.peek() == Some(b'-') {
            self.pos += 1;
        }
        match self.peek() {
            Some(b'0') => {
                self.pos += 1;
            }
            Some(b'1'..=b'9') => {
                self.pos += 1;
                while matches!(self.peek(), Some(b'0'..=b'9')) {
                    self.pos += 1;
                }
            }
            _ => return Err("invalid JSON number".to_string()),
        }
        if self.peek() == Some(b'.') {
            self.pos += 1;
            if !matches!(self.peek(), Some(b'0'..=b'9')) {
                return Err("invalid JSON fraction".to_string());
            }
            while matches!(self.peek(), Some(b'0'..=b'9')) {
                self.pos += 1;
            }
        }
        if matches!(self.peek(), Some(b'e') | Some(b'E')) {
            self.pos += 1;
            if matches!(self.peek(), Some(b'+') | Some(b'-')) {
                self.pos += 1;
            }
            if !matches!(self.peek(), Some(b'0'..=b'9')) {
                return Err("invalid JSON exponent".to_string());
            }
            while matches!(self.peek(), Some(b'0'..=b'9')) {
                self.pos += 1;
            }
        }
        let s = std::str::from_utf8(&self.bytes[start..self.pos]).map_err(|_| "utf8".to_string())?;
        let n = s.parse::<f64>().map_err(|_| "number parse failure".to_string())?;
        Ok(JsonValue::Number(n))
    }

    fn parse_string(&mut self) -> Result<String, String> {
        self.expect(b'"')?;
        let mut out = String::new();
        while let Some(ch) = self.next() {
            match ch {
                b'"' => return Ok(out),
                b'\\' => {
                    let esc = self.next().ok_or_else(|| "unterminated escape".to_string())?;
                    match esc {
                        b'"' => out.push('"'),
                        b'\\' => out.push('\\'),
                        b'/' => out.push('/'),
                        b'b' => out.push('\u{0008}'),
                        b'f' => out.push('\u{000C}'),
                        b'n' => out.push('\n'),
                        b'r' => out.push('\r'),
                        b't' => out.push('\t'),
                        b'u' => {
                            let code = self.parse_hex4()?;
                            let chr = char::from_u32(code).ok_or_else(|| "invalid unicode escape".to_string())?;
                            out.push(chr);
                        }
                        _ => return Err("invalid escape".to_string()),
                    }
                }
                b if b < 0x20 => return Err("control character in string".to_string()),
                b => out.push(b as char),
            }
        }
        Err("unterminated string".to_string())
    }

    fn parse_hex4(&mut self) -> Result<u32, String> {
        let mut code = 0u32;
        for _ in 0..4 {
            let b = self.next().ok_or_else(|| "bad unicode escape".to_string())?;
            code = (code << 4)
                | match b {
                    b'0'..=b'9' => (b - b'0') as u32,
                    b'a'..=b'f' => (b - b'a' + 10) as u32,
                    b'A'..=b'F' => (b - b'A' + 10) as u32,
                    _ => return Err("bad unicode escape".to_string()),
                };
        }
        Ok(code)
    }

    fn parse_array(&mut self) -> Result<JsonValue, String> {
        self.expect(b'[')?;
        self.skip_ws();
        let mut items = Vec::new();
        if self.peek() == Some(b']') {
            self.pos += 1;
            return Ok(JsonValue::Array(items));
        }
        loop {
            items.push(self.parse_value()?);
            self.skip_ws();
            match self.next() {
                Some(b',') => {}
                Some(b']') => break,
                _ => return Err("invalid array separator".to_string()),
            }
        }
        Ok(JsonValue::Array(items))
    }

    fn parse_object(&mut self) -> Result<JsonValue, String> {
        self.expect(b'{')?;
        self.skip_ws();
        let mut map = BTreeMap::new();
        if self.peek() == Some(b'}') {
            self.pos += 1;
            return Ok(JsonValue::Object(map));
        }
        loop {
            self.skip_ws();
            let key = self.parse_string()?;
            self.skip_ws();
            self.expect(b':')?;
            let value = self.parse_value()?;
            map.insert(key, value);
            self.skip_ws();
            match self.next() {
                Some(b',') => {}
                Some(b'}') => break,
                _ => return Err("invalid object separator".to_string()),
            }
        }
        Ok(JsonValue::Object(map))
    }

    fn skip_ws(&mut self) {
        while matches!(self.peek(), Some(b' ' | b'\n' | b'\r' | b'\t')) {
            self.pos += 1;
        }
    }

    fn consume_bytes(&mut self, expected: &[u8]) -> bool {
        if self.bytes.get(self.pos..self.pos + expected.len()) == Some(expected) {
            self.pos += expected.len();
            true
        } else {
            false
        }
    }

    fn expect(&mut self, expected: u8) -> Result<(), String> {
        match self.next() {
            Some(b) if b == expected => Ok(()),
            _ => Err("unexpected character".to_string()),
        }
    }

    fn peek(&self) -> Option<u8> {
        self.bytes.get(self.pos).copied()
    }

    fn next(&mut self) -> Option<u8> {
        let b = self.peek()?;
        self.pos += 1;
        Some(b)
    }
}

impl JsonValue {
    fn as_object(&self) -> Result<&BTreeMap<String, JsonValue>, String> {
        match self {
            JsonValue::Object(m) => Ok(m),
            _ => Err("expected object".to_string()),
        }
    }

    fn as_array(&self) -> Result<&Vec<JsonValue>, String> {
        match self {
            JsonValue::Array(a) => Ok(a),
            _ => Err("expected array".to_string()),
        }
    }

    fn as_bool(&self) -> Result<bool, String> {
        match self {
            JsonValue::Bool(v) => Ok(*v),
            _ => Err("expected bool".to_string()),
        }
    }

    fn as_f64(&self) -> Result<f64, String> {
        match self {
            JsonValue::Number(v) => Ok(*v),
            _ => Err("expected number".to_string()),
        }
    }

    fn as_usize(&self) -> Result<usize, String> {
        let v = self.as_f64()?;
        if cmp_lt(v, 0.0) {
            return Err("expected non-negative integer".to_string());
        }
        let rounded = v.round();
        if realcompare(v, rounded) != EQ {
            return Err("expected integer".to_string());
        }
        Ok(rounded as usize)
    }

    fn as_str(&self) -> Result<&str, String> {
        match self {
            JsonValue::String(s) => Ok(s),
            _ => Err("expected string".to_string()),
        }
    }
}

fn obj_get<'a>(obj: &'a BTreeMap<String, JsonValue>, key: &str) -> Result<&'a JsonValue, String> {
    obj.get(key).ok_or_else(|| format!("missing key: {key}"))
}

fn parse_input(src: &str) -> Result<Input, String> {
    let root = JsonParser::new(src).parse()?;
    let obj = root.as_object()?;

    let numpoints = obj_get(obj, "numpoints")?.as_usize()?;
    let xs = obj_get(obj, "x")?.as_array()?;
    let ys = obj_get(obj, "y")?.as_array()?;
    if xs.len() != numpoints || ys.len() != numpoints {
        return Err("coordinate length mismatch".to_string());
    }
    let mut points = Vec::with_capacity(numpoints);
    for i in 0..numpoints {
        points.push(Point {
            x: xs[i].as_f64()?,
            y: ys[i].as_f64()?,
        });
    }

    let params_obj = obj_get(obj, "parameters")?.as_object()?;
    let parameters = Parameters {
        length1: obj_get(params_obj, "LENGTH1")?.as_f64()?,
        radius1: obj_get(params_obj, "RADIUS1")?.as_f64()?,
        epsilon: obj_get(params_obj, "EPSILON")?.as_f64()?,
        area1: obj_get(params_obj, "AREA1")?.as_f64()?,
        q_pts: obj_get(params_obj, "Q_PTS")?.as_usize()?,
        quads: obj_get(params_obj, "QUADS")?.as_usize()?,
        dist: obj_get(params_obj, "DIST")?.as_f64()?,
        n_pts: obj_get(params_obj, "N_PTS")?.as_usize()?,
        k_pts: obj_get(params_obj, "K_PTS")?.as_usize()?,
        a_pts: obj_get(params_obj, "A_PTS")?.as_usize()?,
        b_pts: obj_get(params_obj, "B_PTS")?.as_usize()?,
        c_pts: obj_get(params_obj, "C_PTS")?.as_usize()?,
        d_pts: obj_get(params_obj, "D_PTS")?.as_usize()?,
        e_pts: obj_get(params_obj, "E_PTS")?.as_usize()?,
        f_pts: obj_get(params_obj, "F_PTS")?.as_usize()?,
        g_pts: obj_get(params_obj, "G_PTS")?.as_usize()?,
        length2: obj_get(params_obj, "LENGTH2")?.as_f64()?,
        radius2: obj_get(params_obj, "RADIUS2")?.as_f64()?,
        area2: obj_get(params_obj, "AREA2")?.as_f64()?,
    };

    let lcm_arr = obj_get(obj, "lcm")?.as_array()?;
    if lcm_arr.len() != 15 {
        return Err("LCM must have 15 rows".to_string());
    }
    let mut lcm = Vec::with_capacity(15);
    for row_val in lcm_arr {
        let row_arr = row_val.as_array()?;
        if row_arr.len() != 15 {
            return Err("LCM must have 15 columns".to_string());
        }
        let mut row = Vec::with_capacity(15);
        for cell in row_arr {
            let connector = match cell.as_str()? {
                "NOTUSED" => Connector::NotUsed,
                "ORR" => Connector::Orr,
                "ANDD" => Connector::Andd,
                _ => return Err("invalid connector".to_string()),
            };
            row.push(connector);
        }
        lcm.push(row);
    }

    let diag_arr = obj_get(obj, "pum_diag")?.as_array()?;
    if diag_arr.len() != 15 {
        return Err("pum_diag must have 15 elements".to_string());
    }
    let mut pum_diag = Vec::with_capacity(15);
    for item in diag_arr {
        pum_diag.push(item.as_bool()?);
    }

    Ok(Input {
        numpoints,
        points,
        parameters,
        lcm,
        pum_diag,
    })
}

fn distance(a: &Point, b: &Point) -> f64 {
    ((a.x - b.x) * (a.x - b.x) + (a.y - b.y) * (a.y - b.y)).sqrt()
}

fn triangle_area(a: &Point, b: &Point, c: &Point) -> f64 {
    (((b.x - a.x) * (c.y - a.y)) - ((c.x - a.x) * (b.y - a.y))).abs() / 2.0
}

fn points_equal(a: &Point, b: &Point) -> bool {
    realcompare(a.x, b.x) == EQ && realcompare(a.y, b.y) == EQ
}

fn angle_satisfies(a: &Point, b: &Point, c: &Point, epsilon: f64) -> bool {
    if points_equal(a, b) || points_equal(c, b) {
        return false;
    }
    let ux = a.x - b.x;
    let uy = a.y - b.y;
    let vx = c.x - b.x;
    let vy = c.y - b.y;
    let dot = ux * vx + uy * vy;
    let nu = (ux * ux + uy * uy).sqrt();
    let nv = (vx * vx + vy * vy).sqrt();
    let mut cosine = dot / (nu * nv);
    if cmp_gt(cosine, 1.0) {
        cosine = 1.0;
    } else if cmp_lt(cosine, -1.0) {
        cosine = -1.0;
    }
    let angle = cosine.acos();
    cmp_lt(angle, PI_VALUE - epsilon) || cmp_gt(angle, PI_VALUE + epsilon)
}

fn min_enclosing_circle_radius(a: &Point, b: &Point, c: &Point) -> f64 {
    let ab = distance(a, b);
    let ac = distance(a, c);
    let bc = distance(b, c);

    let mut longest = ab;
    let mut other1 = ac;
    let mut other2 = bc;
    if cmp_gt(ac, longest) {
        longest = ac;
        other1 = ab;
        other2 = bc;
    }
    if cmp_gt(bc, longest) {
        longest = bc;
        other1 = ab;
        other2 = ac;
    }

    let longest_sq = longest * longest;
    let sum_sq = other1 * other1 + other2 * other2;
    if cmp_ge(longest_sq, sum_sq) {
        longest / 2.0
    } else {
        let area = triangle_area(a, b, c);
        (ab * ac * bc) / (4.0 * area)
    }
}

fn circle_cannot_contain(a: &Point, b: &Point, c: &Point, radius: f64) -> bool {
    cmp_gt(min_enclosing_circle_radius(a, b, c), radius)
}

fn circle_can_contain(a: &Point, b: &Point, c: &Point, radius: f64) -> bool {
    cmp_le(min_enclosing_circle_radius(a, b, c), radius)
}

fn quadrant(p: &Point) -> usize {
    if cmp_ge(p.x, 0.0) && cmp_ge(p.y, 0.0) {
        1
    } else if cmp_lt(p.x, 0.0) && cmp_ge(p.y, 0.0) {
        2
    } else if cmp_le(p.x, 0.0) && cmp_lt(p.y, 0.0) {
        3
    } else {
        4
    }
}

fn distance_from_line(point: &Point, start: &Point, end: &Point) -> f64 {
    if points_equal(start, end) {
        distance(point, start)
    } else {
        let numerator =
            ((end.y - start.y) * point.x - (end.x - start.x) * point.y + end.x * start.y - end.y * start.x).abs();
        let denominator = distance(start, end);
        numerator / denominator
    }
}

fn lic1(input: &Input) -> bool {
    input
        .points
        .windows(2)
        .any(|w| cmp_gt(distance(&w[0], &w[1]), input.parameters.length1))
}

fn lic2(input: &Input) -> bool {
    input
        .points
        .windows(3)
        .any(|w| circle_cannot_contain(&w[0], &w[1], &w[2], input.parameters.radius1))
}

fn lic3(input: &Input) -> bool {
    input
        .points
        .windows(3)
        .any(|w| angle_satisfies(&w[0], &w[1], &w[2], input.parameters.epsilon))
}

fn lic4(input: &Input) -> bool {
    input
        .points
        .windows(3)
        .any(|w| cmp_gt(triangle_area(&w[0], &w[1], &w[2]), input.parameters.area1))
}

fn lic5(input: &Input) -> bool {
    input.points.windows(input.parameters.q_pts).any(|w| {
        let mut seen = [false; 4];
        for point in w {
            seen[quadrant(point) - 1] = true;
        }
        seen.iter().filter(|v| **v).count() > input.parameters.quads
    })
}

fn lic6(input: &Input) -> bool {
    input
        .points
        .windows(2)
        .any(|w| cmp_lt(w[1].x - w[0].x, 0.0))
}

fn lic7(input: &Input) -> bool {
    if input.numpoints < 3 {
        return false;
    }
    let n_pts = input.parameters.n_pts;
    for start in 0..=input.numpoints - n_pts {
        let first = &input.points[start];
        let last = &input.points[start + n_pts - 1];
        for idx in start + 1..start + n_pts - 1 {
            let d = distance_from_line(&input.points[idx], first, last);
            if cmp_gt(d, input.parameters.dist) {
                return true;
            }
        }
    }
    false
}

fn lic8(input: &Input) -> bool {
    if input.numpoints < 3 {
        return false;
    }
    let gap = input.parameters.k_pts + 1;
    (0..input.numpoints - gap).any(|i| cmp_gt(distance(&input.points[i], &input.points[i + gap]), input.parameters.length1))
}

fn lic9(input: &Input) -> bool {
    if input.numpoints < 5 {
        return false;
    }
    let step1 = input.parameters.a_pts + 1;
    let step2 = step1 + input.parameters.b_pts + 1;
    (0..input.numpoints - step2).any(|i| {
        circle_cannot_contain(
            &input.points[i],
            &input.points[i + step1],
            &input.points[i + step2],
            input.parameters.radius1,
        )
    })
}

fn lic10(input: &Input) -> bool {
    if input.numpoints < 5 {
        return false;
    }
    let step1 = input.parameters.c_pts + 1;
    let step2 = step1 + input.parameters.d_pts + 1;
    (0..input.numpoints - step2).any(|i| {
        angle_satisfies(
            &input.points[i],
            &input.points[i + step1],
            &input.points[i + step2],
            input.parameters.epsilon,
        )
    })
}

fn lic11(input: &Input) -> bool {
    if input.numpoints < 5 {
        return false;
    }
    let step1 = input.parameters.e_pts + 1;
    let step2 = step1 + input.parameters.f_pts + 1;
    (0..input.numpoints - step2)
        .any(|i| cmp_gt(triangle_area(&input.points[i], &input.points[i + step1], &input.points[i + step2]), input.parameters.area1))
}

fn lic12(input: &Input) -> bool {
    if input.numpoints < 3 {
        return false;
    }
    let gap = input.parameters.g_pts + 1;
    (0..input.numpoints - gap).any(|i| cmp_lt(input.points[i + gap].x - input.points[i].x, 0.0))
}

fn lic13(input: &Input) -> bool {
    if input.numpoints < 3 {
        return false;
    }
    let gap = input.parameters.k_pts + 1;
    let mut found_gt = false;
    let mut found_lt = false;
    for i in 0..input.numpoints - gap {
        let d = distance(&input.points[i], &input.points[i + gap]);
        if cmp_gt(d, input.parameters.length1) {
            found_gt = true;
        }
        if cmp_lt(d, input.parameters.length2) {
            found_lt = true;
        }
    }
    found_gt && found_lt
}

fn lic14(input: &Input) -> bool {
    if input.numpoints < 5 {
        return false;
    }
    let step1 = input.parameters.a_pts + 1;
    let step2 = step1 + input.parameters.b_pts + 1;
    let mut found_cannot = false;
    let mut found_can = false;
    for i in 0..input.numpoints - step2 {
        let a = &input.points[i];
        let b = &input.points[i + step1];
        let c = &input.points[i + step2];
        if circle_cannot_contain(a, b, c, input.parameters.radius1) {
            found_cannot = true;
        }
        if circle_can_contain(a, b, c, input.parameters.radius2) {
            found_can = true;
        }
    }
    found_cannot && found_can
}

fn lic15(input: &Input) -> bool {
    if input.numpoints < 5 {
        return false;
    }
    let step1 = input.parameters.e_pts + 1;
    let step2 = step1 + input.parameters.f_pts + 1;
    let mut found_gt = false;
    let mut found_lt = false;
    for i in 0..input.numpoints - step2 {
        let area = triangle_area(&input.points[i], &input.points[i + step1], &input.points[i + step2]);
        if cmp_gt(area, input.parameters.area1) {
            found_gt = true;
        }
        if cmp_lt(area, input.parameters.area2) {
            found_lt = true;
        }
    }
    found_gt && found_lt
}

fn compute_cmv(input: &Input) -> Vec<bool> {
    vec![
        lic1(input),
        lic2(input),
        lic3(input),
        lic4(input),
        lic5(input),
        lic6(input),
        lic7(input),
        lic8(input),
        lic9(input),
        lic10(input),
        lic11(input),
        lic12(input),
        lic13(input),
        lic14(input),
        lic15(input),
    ]
}

fn compute_pum(input: &Input, cmv: &[bool]) -> Vec<Vec<bool>> {
    let mut pum = vec![vec![true; 15]; 15];
    for i in 0..15 {
        for j in 0..15 {
            if i == j {
                pum[i][j] = input.pum_diag[i];
            } else {
                pum[i][j] = match input.lcm[i][j] {
                    Connector::NotUsed => true,
                    Connector::Orr => cmv[i] || cmv[j],
                    Connector::Andd => cmv[i] && cmv[j],
                };
            }
        }
    }
    pum
}

fn compute_fuv(pum: &[Vec<bool>]) -> Vec<bool> {
    (0..15)
        .map(|i| !pum[i][i] || pum[i].iter().all(|v| *v))
        .collect()
}

fn render_bool(v: bool) -> &'static str {
    if v { "true" } else { "false" }
}

fn bool_vec_json(values: &[bool]) -> String {
    let mut out = String::from("[");
    for (i, value) in values.iter().enumerate() {
        if i > 0 {
            out.push(',');
        }
        out.push_str(render_bool(*value));
    }
    out.push(']');
    out
}

fn bool_matrix_json(matrix: &[Vec<bool>]) -> String {
    let mut out = String::from("[");
    for (i, row) in matrix.iter().enumerate() {
        if i > 0 {
            out.push(',');
        }
        out.push_str(&bool_vec_json(row));
    }
    out.push(']');
    out
}

fn main() {
    let mut input_text = String::new();
    io::stdin().read_to_string(&mut input_text).unwrap();
    let input = parse_input(&input_text).unwrap();
    let cmv = compute_cmv(&input);
    let pum = compute_pum(&input, &cmv);
    let fuv = compute_fuv(&pum);
    let launch = fuv.iter().all(|v| *v);

    let output = format!(
        "{{\"cmv\":{},\"pum\":{},\"fuv\":{},\"launch\":{}}}",
        bool_vec_json(&cmv),
        bool_matrix_json(&pum),
        bool_vec_json(&fuv),
        render_bool(launch)
    );
    println!("{output}");
}
